@import url('https://content.powerapps.com/resource/powerappsportal/fonts/open-sans/v34/400-italic.css');


/* ===============================
   GLOBAL STYLES
================================ */
body {
    background-color: #f5f7fb;
    font-family: 'Segoe UI', Arial, sans-serif;
    color: #1f2937;
}

/* ===============================
   HEADER (NAVBAR)
================================ */
.navbar {
    background-color: #ffffff !important;
    border-bottom: 1px solid #e5e7eb;
    padding: 12px 24px;
    box-shadow: 0 2px 6px rgba(0,0,0,0.04);
}

.navbar-brand {
    font-size: 18px;
    font-weight: 600;
}

/* ===============================
   MAIN FORM CONTAINER (ONLY BOX ✅)
================================ */
.entity-form {
    padding: 32px;
}

/* ===============================
   REMOVE INNER BOXES ❌
================================ */
.entity-form fieldset {
    border: none !important;
    padding: 0 !important;
    margin: 0 !important;
    background: transparent !important;
    box-shadow: none !important;
}

/* remove any section wrapping */
.entity-form .section {
    border: none !important;
    padding: 0 !important;
    margin: 0 !important;
    background: none !important;
}

/* ===============================
   SECTION TITLES
================================ */
.entity-form h2,
.entity-form h3 {
    font-size: 20px;
    font-weight: 600;
    margin-top: 25px;
    margin-bottom: 15px;
    color: #111827;
}

/* ===============================
   FORM GROUP SPACING
================================ */
.form-group {
    margin-bottom: 20px;
}

/* ===============================
   LABELS
================================ */
.control-label {
    font-size: 13px;
    font-weight: 500;
    color: #374151;
    margin-bottom: 6px;
}

.control-label span.required {
    color: #dc2626;
}

/* ===============================
   INPUT FIELDS
================================ */
input,
select,
textarea {
    width: 100%;
    height: 42px;
    border-radius: 8px !important;
    border: 1px solid #d1d5db !important;
    padding: 8px 12px;
    font-size: 14px;
    background-color: #ffffff;
    transition: all 0.2s ease;
}

/* textarea fix */
textarea {
    height: auto;
}

/* hover */
input:hover,
select:hover {
    border-color: #9ca3af;
}

/* focus */
input:focus,
select:focus,
textarea:focus {
    border-color: #2563eb !important;
    box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.15);
    outline: none;
}

/* ===============================
   AI ASSIST BOX (BANNER STYLE ✅)
================================ */
.alert-info {
    background: #eef2ff;
    border: none !important;
    border-left: 4px solid #4f46e5;
    border-radius: 8px;
    padding: 14px 16px;
    margin-bottom: 20px;
    font-size: 14px;
    color: #1e1b4b;
}

/* ===============================
   GRID / COLUMN SPACING
================================ */
.row {
    margin-left: -10px;
    margin-right: -10px;
}

.col-md-6 {
    padding: 10px;
}

/* ===============================
   BUTTON (PRIMARY CTA ✅)
================================ */
.btn-primary,
button[type="submit"] {
    background-color: #2563eb !important;
    border: none !important;
    padding: 12px 24px;
    border-radius: 8px;
    font-weight: 600;
    font-size: 14px;
    transition: all 0.3s ease;
}

/* hover */
.btn-primary:hover,
button[type="submit"]:hover {
    background-color: #1d4ed8 !important;
}

/* button alignment */
.actions {
    margin-bottom: 24px !important;
    margin-left: 63px !important;
    margin-top: 0px !important;
    border-top: none !important;
    padding-top:0px !important
}

/* ===============================
   TEXT (STATUS ETC.)
================================ */
.entity-form p,
.entity-form span {
    font-size: 14px;
    color: #4b5563;
}

/* ===============================
   MOBILE RESPONSIVE
================================ */
@media (max-width: 768px) {
    .entity-form {
        padding: 20px;
        margin: 20px;
    }

    .col-md-6 {
        width: 100%;
        padding: 5px;
    }

    .btn-primary {
        width: 100%;
    }
}

/* ===============================
   FINAL CLEANUP
================================ */

/* remove all default borders */
fieldset {
    border: none !important;
}

/* smooth UI */
* {
    transition: all 0.15s ease-in-out;
}
crmEntityFormView, .entitylist, .modal-content, .popover-content {
    background-color: #FFFFFF;
    color: #000000;
    border: 1px solid #f2f2f2;
    border-radius: 12px !important;
}"
}
